INSERT INTO public.photos VALUES (21862, 'Santa Isabel 1934', 'Imagen parcial del original servicio de gasolina, agua y aire de la Casa Us‚Ēú√≠n ubicado junto al puente del G‚Ēú√≠llego y la carretera de Catalu‚Ēú‚Ėía, a la entrada del barrio de Santa Isabel. En este establecimiento pod‚Ēú¬°an adquirirse, adem‚Ēú√≠s, ultramarinos y fiambres, lubricantes, piensos, e incluso cemento de Morata. Por su estrat‚Ēú¬ģgica situaci‚Ēú‚Ēān, este servicio fue ampliado y reformado en varias ocasiones. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'SANTA ISABEL', 41.67031700, -0.83966900, '0101000020E61000007AE1CE8591DEEABFF6798CF2CCD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36327616391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36327616391.webp', 'https://www.flickr.com/photos/zaragozaantigua/36327616391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21967, 'Santa Isabel 1941', 'Imagen de la veterana estaci‚Ēú‚Ēān de servicio del barrio de Santa Isabel, un poco despu‚Ēú¬ģs de cruzar el puente del G‚Ēú√≠llego, en la carretera a Barcelona. En la imagen, un autob‚Ēú‚ēĎs de la l‚Ēú¬°nea del G‚Ēú√≠llego, con terminal en la Plaza de Ari‚Ēú‚Ėío. Unos a‚Ēú‚Ėíos despu‚Ēú¬ģs, una profunda remodelaci‚Ēú‚Ēān expansiva le dar‚Ēú¬°a a esta gasolinera un aire m‚Ēú√≠s "moderno". Fuente visual: www.avvsantaisabel.org/.', 1941, 1941, 1941, 'Anos 40', 'SANTA ISABEL', 41.67031700, -0.83966900, '0101000020E61000007AE1CE8591DEEABFF6798CF2CCD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22417193391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22417193391.webp', 'https://www.flickr.com/photos/zaragozaantigua/22417193391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23746, 'Ctra. de Barcelona c.1900', 'Imagen capturada en la carretera de Barcelona con el espectacular fondo de la fachada principal de los grandes pabellones de la antigua f‚Ēú√≠brica harinera de Villarroya y Castellano, construidos en 1857 tras el gran incendio de 1855, que en 1899 hab‚Ēú¬°a sido reconvertida en factor‚Ēú¬°a azucarera con la denominaci‚Ēú‚Ēān de Nueva Azucarera "La Raperie". En ellos se habilitaron habitaciones para los jefes de la azucarera, una capilla, almacenes y locales para el personal facultativo, la dependencia y algunos talleres. En las traseras de estos inmuebles se abr‚Ēú¬°a un gran patio o jard‚Ēú¬°n central por el que flu‚Ēú¬°a al aire la acequia Urdana. En primer t‚Ēú¬ģrmino, aspecto del tr‚Ēú√≠fico de esta v‚Ēú¬°a de comunicaci‚Ēú‚Ēān, y en la esquina de la izquierda detalle de la sombra proyectada por el fot‚Ēú‚Ēāgrafo de esta imagen y sus acompa‚Ēú‚Ėíantes.', 1900, 1900, 1900, 'Anos 1900', 'SANTA ISABEL', 41.66965800, -0.83886600, '0101000020E6100000253E7782FDD7EABF9CC0745AB7D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15488834427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15488834427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15488834427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23748, 'Balay 1969', 'Foto Jos‚Ēú¬ģ Borobio, 1969. Nuevo edificio de la factor‚Ēú¬°a de electrodom‚Ēú¬ģsticos Balay en Zaragoza, construido en la avenida de la Industria 49 del barrio de Monta‚Ēú‚Ėíana, en 1968. La f‚Ēú√≠brica se hab‚Ēú¬°a instalado all‚Ēú¬° en 1956. Fuente visual: "Una mirada a trav‚Ēú¬ģs de la arquitectura: Regino y Jos‚Ēú¬ģ Borobio Ojeda", Daniel Estab‚Ēú¬ģn Boldova, 2013.', 1969, 1969, 1969, 'Anos 60', 'SANTA ISABEL', 41.67191000, -0.83680800, '0101000020E610000054FF209221C7EABF7CED992501D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15531853598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15531853598.webp', 'https://www.flickr.com/photos/zaragozaantigua/15531853598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23758, 'Balay 1956', 'Vista a‚Ēú¬ģrea en 1956 de la nueva factor‚Ēú¬°a de electrodom‚Ēú¬ģsticos Balay de Zaragoza, en la confluencia de las carreteras de Santa Isabel (abajo, junto a la gasolinera triangular con torrecilla) y de Monta‚Ēú‚Ėíana (a la derecha, hoy avenida de la Industria). El negocio proven‚Ēú¬°a de su anterior ubicaci‚Ēú‚Ēān en la calle Pradilla 58. Fuente: Exposici‚Ēú‚Ēān "‚Ēú√ęrase una vez Balay", Zaragoza, 2015.', 1956, 1956, 1956, 'Anos 50', 'SANTA ISABEL', 41.67096300, -0.83922100, '0101000020E6100000AEB9A3FFE5DAEABFBCE9961DE2D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21191785903.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21191785903.webp', 'https://www.flickr.com/photos/zaragozaantigua/21191785903/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21216, 'Zaragoza desde el G‚Ēú√≠llego c.1908', 'Foto Gabriel Faci/Archivo DARA. Toma de arbolillo ribere‚Ēú‚Ėío en primer plano, con zagales en la ribera del r‚Ēú¬°o G‚Ēú√≠llego y vista de Zaragoza al fondo, con sus torres. Fuente visual: AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'SANTA ISABEL', 41.66696800, -0.84112200, '0101000020E61000008D463EAF78EAEABF40BD19355FD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15423220956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15423220956.webp', 'https://www.flickr.com/photos/zaragozaantigua/15423220956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21140, 'La Monta‚Ēú‚Ėíanesa 1897', '1897. F‚Ēú√≠brica de papel "La Monta‚Ēú‚Ėíanesa" en el barrio rural de Monta‚Ēú‚Ėíana de Zaragoza, donde contin‚Ēú‚ēĎa. Fundada en 1867 bajo la raz‚Ēú‚Ēān social "Sorogoyen y Compa‚Ēú‚Ėí‚Ēú¬°a", cambiada m‚Ēú√≠s tarde por la de "Villarroya y Compa‚Ēú‚Ėí‚Ēú¬°a", y transformada en 1900 en Sociedad An‚Ēú‚Ēānima con la denominaci‚Ēú‚Ēān "La Monta‚Ēú‚Ėíanesa", con Francisco Villarroya de presidente. Fuente visual: M‚Ē¨¬¨ Pilar Biel Ib‚Ēú√≠‚Ēú‚Ėíez, Zaragoza y la industrializaci‚Ēú‚Ēān: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'MONTA‚Ēú√¶ANA', 41.69301400, -0.82495100, '0101000020E61000000CAEB9A3FF65EABFC7D5C8AEB4D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871673588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871673588.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871673588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22812, 'La Monta‚Ēú‚Ėíanesa 1973', 'In‚Ēú¬ģdita vista a‚Ēú¬ģrea del complejo fabril de papel y cart‚Ēú‚Ēān ondulado "La Monta‚Ēú‚Ėíanesa S.A." fundada en 1867, recrecida en varias ocasiones e integrada desde 1969 en el grupo Sarri‚Ēú‚Ēā Compa‚Ēú‚Ėí‚Ēú¬°a Papelera de Leiza, S.A., cuya denominaci‚Ēú‚Ēān local se derivaba del hecho de estar enclavada en este singular barrio rural zaragozano elongado en torno a la carretera del mismo nombre. En primer t‚Ēú¬ģrmino, el camino del Cementerio de este barrio arranca desde la carretera de Monta‚Ēú‚Ėíana, frente al que se localiza el ingreso a la factor‚Ēú¬°a a la altura del n‚Ēú‚ēĎmero 109. Hacia el fondo y delimitando el per‚Ēú¬°metro fabril, la acequia de Urd‚Ēú√≠n, y en el extremo superior, el cauce del r‚Ēú¬°o G‚Ēú√≠llego. Esta importante f‚Ēú√≠brica conocer‚Ēú¬°a luego m‚Ēú√≠s ampliaciones y nuevos cambios de titularidad empresarial.', 1973, 1973, 1973, 'Anos 70', 'MONTA‚Ēú√¶ANA', 41.69369600, -0.82463900, '0101000020E6100000553200547163EABFDAAED007CBD84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51553373849.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51553373849.webp', 'https://www.flickr.com/photos/zaragozaantigua/51553373849/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21800, 'Avenida MZA 1931', 'Ese canicular d‚Ēú¬°a de julio, Mar‚Ēú¬°n Chivite hizo una de sus estupendas fotograf‚Ēú¬°as, la que da pie a esta entrada, pero el medio que la public‚Ēú‚Ēā luego (el m‚Ēú√≠s antiguo de la regi‚Ēú‚Ēān aragonesa), la considera del montonaje, as‚Ēú¬° que apenas queda hoy como un borr‚Ēú‚Ēān en grisalla sin demasiado atractivo. Vamos a homenajearla como se merece. Se trata de una ins‚Ēú‚Ēālita imagen de la nov‚Ēú¬°sima, y reci‚Ēú¬ģn abierta al tr‚Ēú√≠fico, "Avenida de MZA", as‚Ēú¬° denominada por la inmediata vecindad, a la derecha, de la zanja del ferrocarril MZA de los directos. La captura se ha realizado, viniendo desde el paseo de Sagasta, casi en la intersecci‚Ēú‚Ēān de este nuevo vial con el camino de las Torres, que lo cruza de derecha a izquierda. A la izquierda, los muros perimetrales donde se estaba comenzando la construcci‚Ēú‚Ēān del nuevo convento-colegio de los PP. Agustinos, seg‚Ēú‚ēĎn proyecto de Miguel ‚Ēú√ľngel Navarro. A la derecha, sobre la zanja, la sombra de uno de los puentecillos para paso peatonal. M‚Ēú√≠s a la derecha, ‚Ēú√≠rboles del camino de las Alcachoferas. El cauce al aire de la acequia de San Jos‚Ēú¬ģ queda justo a las espaldas del fot‚Ēú‚Ēāgrafo. Este tramo de la nueva avenida, hasta su cruce con el camino de San Jos‚Ēú¬ģ al fondo, era tambi‚Ēú¬ģn denominado "calle de Fletas", por la cercana y antigua Torre agr‚Ēú¬°cola de ese nombre, al fondo, a la derecha. La valla de madera abierta, en primer plano, nos invita a la inauguraci‚Ēú‚Ēān de este vial, casi 85 a‚Ēú‚Ėíos despu‚Ēú¬ģs. Adelante. Fuente visual: Foto Mar‚Ēú¬°n Chivite, para Heraldo de Arag‚Ēú‚Ēān', 1931, 1931, 1931, 'Anos 30', 'SAN JOS‚Ēú√ę', 41.64104200, -0.88364700, '0101000020E610000021ACC612D646ECBF64AE0CAA0DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26212243314.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26212243314.webp', 'https://www.flickr.com/photos/zaragozaantigua/26212243314/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21898, 'Hospital de italianos c.1938', 'Sonriente y luminoso posado de oficiales y enfermeras en el patio del nuevo convento-colegio de los P.P. agustinos en el camino de las Torres, habilitado como hospital de legionarios italianos durante la ‚Ēú‚ēĎltima guerra civil. Al fondo, el pa‚Ēú‚Ėío noroccidental del patio.', 1938, 1938, 1938, 'Anos 30', 'SAN JOS‚Ēú√ę', 41.64113600, -0.88244600, '0101000020E6100000718DCF64FF3CECBFE62494BE10D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51217718273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51217718273.webp', 'https://www.flickr.com/photos/zaragozaantigua/51217718273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21916, 'Hospitales de Miraflores 1938', 'In‚Ēú¬ģdita imagen capturada en el interior del extenso terreno ocupado por el colegio-seminario de los PP. agustinos de Miraflores. En una zona de firme irregular junto al front‚Ēú‚Ēān aparece una canasta de baloncesto sin uso entre tiendas de campa‚Ēú‚Ėía se‚Ēú‚Ėíaladas con la Cruz Roja. En el edificio principal de este colegio a‚Ēú‚ēĎn no terminado (a espaldas de esta foto) Falange instal‚Ēú‚Ēā una √Ē√á¬£oficina de investigaci‚Ēú‚Ēān√Ē√á√ė para detener, torturar y ejecutar extrajudicialmente infieles a la sublevaci‚Ēú‚Ēān militar de 1936, y aqu‚Ēú¬° se estableci‚Ēú‚Ēā tambi‚Ēú¬ģn un cuartel y un hospital de sangre. Al fondo, en el antiguo barrio de Cartier destaca el edificio de las escuelas de la calle de Abad‚Ēú¬°a (actual CEIP San Jose de Calasanz) inaugurado en 1935 en la esquina entre la calle de Abad‚Ēú¬°a y el callej‚Ēú‚Ēān de la Bailera, junto a la proyectada y no realizada avenida Perimetral y que en 1937 fue reutilizado como hospital de sangre para tropas italianas.', 1938, 1938, 1938, 'Anos 30', 'SAN JOS‚Ēú√ę', 41.64085800, -0.88079300, '0101000020E61000009B7631CD742FECBFA3B08BA207D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53214894398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53214894398.webp', 'https://www.flickr.com/photos/zaragozaantigua/53214894398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21998, 'C.‚Ē¨‚ēĎ de las Torres c.1941', 'Imagen de la fachada principal del nuevo convento-colegio de los PP. Agustinos del camino de las Torres, esquina (a la derecha) con la calle de Fletas, y la zanja del ferrocarril de Zaragoza a Barcelona. Este edificio fue dise‚Ēú‚Ėíado por Miguel ‚Ēú√ľngel Navarro P‚Ēú¬ģrez, y la descomunal iglesia vinculada a este proyecto estaba prevista en la zona trasera del ala izquierda. A la espalda del fot‚Ēú‚Ēāgrafo flu‚Ēú¬°a al aire la antigua acequia de las Adulas, ahora denominada de San Jos‚Ēú¬ģ. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1941, 1941, 1941, 'Anos 40', 'SAN JOS‚Ēú√ę', 41.64112000, -0.88321900, '0101000020E61000001C96067E5443ECBFE0675C3810D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33287643572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33287643572.webp', 'https://www.flickr.com/photos/zaragozaantigua/33287643572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22224, 'P.‚Ē¨‚ēĎ de Fernando el Cat‚Ēú‚Ēālico 1958', 'Imagen capturada desde la altura del moderno inmueble del n‚Ē¨‚ēĎ 58 del paseo de Fernando el Cat‚Ēú‚Ēālico, y centrada en las instalaciones de la Editorial Luis Vives S.A., con el aspecto conferido tras la notable ampliaci‚Ēú‚Ēān realizada en 1950 con dise‚Ēú‚Ėío de los hermanos Borobio, sobre la original planta ideada por ellos mismos en 1940. A la izquierda, la calle de Luis Vives, y al fondo, traseras de la Harinera Imperial junto al Canal Imperial de Arag‚Ēú‚Ēān, de la que se destaca su chimenea. En la zona central, parque de Primo de Rivera del que emerge el Monumento al rey Alfonso I en el Cabezo de Buenavista. Esta imagen, coloreada, fue profusamente utilizada como icono publicitario de los libros o textos escolares de la Editorial Edelvives.', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.63825300, -0.89686100, '0101000020E6100000F5D901D715B3ECBF75C93846B2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48986825551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48986825551.webp', 'https://www.flickr.com/photos/zaragozaantigua/48986825551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22017, 'Camino de las Torres c.1941', 'Imagen capturada en altura desde la altura del n‚Ē¨‚ēĎ 24 de la calle de Jes‚Ēú‚ēĎs Com‚Ēú¬°n, antigua del Alba, con una interesante vista parcial del extenso per‚Ēú¬°metro del colegio de San Agust‚Ēú¬°n sito en el camino de las Torres, angular a la derecha a la avenida MZA. Dise‚Ēú‚Ėíado por Miguel ‚Ēú√ľngel Navarro P‚Ēú¬ģrez en 1930, fue construido entre 1931 y 1935, si bien no se finalizaron todas las instalaciones previstas, entre ella la gran iglesia de Santa Rita de Casia. Durante la Guerra Civil fue reconvertido en hospital para soldados italianos heridos en combate, y hubo de esperar hasta 1941 para ser inaugurado, por fin, como colegio y convento. En primer t‚Ēú¬ģrmino y a la izquierda, acequia al aire de San Jos‚Ēú¬ģ descendente por el camino de las Torres. A la derecha, la zanja del ferrocarril de los directos a Barcelona y alguno de los puentecillos de paso peatonal. Sobre el camino de las Alcachoferas destaca la chimenea de la f‚Ēú√≠brica de cervezas La Zaragozana. Al fondo, la torre de Fletas, que tambi‚Ēú¬ģn daba nombre a este extra‚Ēú‚Ėío vial entre la avenida de San Jos‚Ēú¬ģ y el camino de las Torres.', 1941, 1941, 1941, 'Anos 40', 'SAN JOS‚Ēú√ę', 41.64117600, -0.88268200, '0101000020E610000068925852EE3EECBF747D1F0E12D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49420633858.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49420633858.webp', 'https://www.flickr.com/photos/zaragozaantigua/49420633858/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22105, 'La Zaragozana c.1950', 'Interior del recinto de la f‚Ēú√≠brica de cervezas La Zaragozana, domiciliada en la calle Ram‚Ēú‚Ēān Berenguer IV 1 y construida en 1900. Fuente visual: Colecci‚Ēú‚Ēān Jos‚Ēú¬ģ Mar‚Ēú¬°a Ballest‚Ēú¬°n Miguel', 1950, 1950, 1950, 'Anos 50', 'SAN JOS‚Ēú√ę', 41.63787300, -0.88104100, '0101000020E6100000A2EC2DE57C31ECBF2E008DD2A5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20985831439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20985831439.webp', 'https://www.flickr.com/photos/zaragozaantigua/20985831439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22201, 'F.C. a Barcelona 1959', 'Imagen capturada durante las obras de establecimiento de la doble v‚Ēú¬°a ferroviaria entre las estaciones de Campo Sepulcro y Miraflores (l‚Ēú¬°nea de Barcelona). La imagen se ha tomado desde uno de los pasos elevados que, en el tramo entre el camino de las Torres, y la avenida de San Jos‚Ēú¬ģ, salvaban la zanja del ferrocarril. A la izquierda, la antigua calle de Fletas, y el punto m‚Ēú√≠s al sureste del muro perimetral que delimitaba el enorme colegio de los PP. Agustinos, hasta las inmediaciones del antiguo callej‚Ēú‚Ēān de Bailera y el colegio de San Jos‚Ēú¬ģ de Calasanz. A la derecha, y al fondo, fachada de los bloques recayentes a la calle Lausana, conducente a general Mill‚Ēú√≠n Astray, y Suiza. Una vaporosa (tal vez una "Mikado") se encamina con su regular traqueteo hacia la estaci‚Ēú‚Ēān Campo Sepulcro. El despejado panorama de esa zona de huerta pronto mutar‚Ēú¬°a, en su parte derecha, con nuevos bloques, 2,5 veces m‚Ēú√≠s de altos, de media, y nuevos viales. Al desdoblamiento de la v‚Ēú¬°a le seguir‚Ēú¬°a luego el cubrimiento hasta el camino del Puente del Virrey, y el advenimiento de la denominaci‚Ēú‚Ēān de Tenor Fleta a la avenida resultante. Fuente visual: Archivo Municipal de Zaragoza.', 1959, 1959, 1959, 'Anos 50', 'SAN JOS‚Ēú√ę', 41.63963900, -0.88104000, '0101000020E61000008CF84ECC7A31ECBF821FD5B0DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33603130385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33603130385.webp', 'https://www.flickr.com/photos/zaragozaantigua/33603130385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22343, 'PP. Agustinos c.1966', 'Captura, en el cruce de Camino de las Torres con Tenor Fleta, de la gigantesca manzana (por el tama‚Ēú‚Ėío, casi calabaza, y de las gordas) en la que los PP Agustinos ten‚Ēú¬°an colegio, varios campos de f‚Ēú‚ēĎtbol, zonas verdes, y un proyecto de magna iglesia que no pas‚Ēú‚Ēā de proyecto. Inmediatamente, en el pedazo de Tenor Fleta visible, la reci‚Ēú¬ģn recubierta trinchera del ferrocarril a Barcelona, con restos a‚Ēú‚ēĎn de obra. La vista parcialmente a‚Ēú¬ģrea, realizada desde el bloque de viviendas n‚Ē¨‚ēĎ 104 de Camino de las Torres, permite una contemplaci‚Ēú‚Ēān de los entonces apacibles y verdosos jardines internos del Colegio, con c‚Ēú¬ģsped, setos, ‚Ēú√≠rboles...y suelo de tierra. A la derecha, tras las lejos muros perimetrales del colegio, los campos de cultivo de Miraflores, a‚Ēú‚ēĎn cultivados de herb‚Ēú√≠ceas. Al fondo, a la izquierda, los bloques de vivienda de la calle Lorenzo Pardo, Licorera (con una vista del edificio de la antigua f‚Ēú√≠brica), y los bloques de viviendas de la Avenida de S. Jos‚Ēú¬ģ... todo ello es visible porque la imagen es anterior a la prolongaci‚Ēú‚Ēān de Marina Moreno, y la posterior erecci‚Ēú‚Ēān de todos los altos bloques de la actual Ces‚Ēú√≠reo Alierta, en la acera de los impares, y la acera de los pares, por supuesto. Tambi‚Ēú¬ģn es visible el entorno de la Parroquia de S. Agust‚Ēú¬°n, con su pabell‚Ēú‚Ēān, el arranque de la calle Cartagena. Ya a la derecha, las traseras de los bloques de S. Jos‚Ēú¬ģ, Domingo Lobera. La foto parece de hace cuatro d‚Ēú¬°as, pero los cambios que han de producirse en estaq zona son de consideraci‚Ēú‚Ēān. Fuente visual: Im‚Ēú√≠genes Antiguas de Zaragoza.', 1966, 1966, 1966, 'Anos 60', 'SAN JOS‚Ēú√ę', 41.64112000, -0.88321900, '0101000020E61000001C96067E5443ECBFE0675C3810D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20224425316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20224425316.webp', 'https://www.flickr.com/photos/zaragozaantigua/20224425316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22469, 'Calle de Pradilla 1962', 'Imagen capturada desde la terraza del n‚Ē¨‚ēĎ 14 de la calle del Marqu‚Ēú¬ģs de Ahumada, vivienda unifamiliar de 1942 dise‚Ēú‚Ėíada por Enrique Vincenti Bravo. La vista, orientada hacia el suroeste, nos retrotrae a los espacios y escalas edilicias del urbanismo del antiguo barrrio de los "Chiflaos", en este caso las traseras ajardinadas de algunas de las parcelas de la calle de Pradilla que, en dencenso, arrancaban en la antigua avenida del Siglo XX, luego paseo de Cu‚Ēú¬ģllar. En primer plano, el jard‚Ēú¬°n y construcci‚Ēú‚Ēān secundaria del propio edificio desde donde se toma la fotograf‚Ēú¬°a. A la derecha, el exuberante seto sobre la medianera con el n‚Ē¨‚ēĎ 12 de Marqu‚Ēú¬ģs de Ahumada, cuya casa era gemela del n‚Ē¨‚ēĎ 14, y que luego fue derribada. En el centro de la imagen, las traseras ajardinadas de las antiguas parcelas de la calle de Pradilla n‚Ē¨‚ēĎ 34, n‚Ē¨‚ēĎ 35, n‚Ē¨‚ēĎ 37, y n‚Ē¨‚ēĎ 38, esta con un destacado torreoncillo se‚Ēú‚Ėía de identidad de varias de las construcciones de la zona. A la izquierda, un poco m‚Ēú√≠s al fondo, vista parcial del torreoncillo, este cubierto a cuatro aguas, de la antigua parcela n‚Ē¨‚ēĎ 13 y 14 de la misma calle. Al fondo, a la derecha, el edificio de la antigua parcela del n‚Ē¨‚ēĎ 37 del paseo de Cu‚Ēú¬ģllar. Todas estas construcciones luego fueron derribadas y sustituidas por edificios de viviendas m‚Ēú√≠s modernos, y todas las zonas ajardinadas de la imagen fueron incorporadas a los nuevos espacios residenciales resultantes. De esta zona s‚Ēú‚Ēālo perdura la parcela del actual n‚Ē¨‚ēĎ 19 de Pradilla, y la parcela desde donde se ha capturado esta imagen. Fuente visual: exclusiva aportaci‚Ēú‚Ēān de la colecci‚Ēú‚Ēān de Vicente Garc‚Ēú¬ģs al "Gran Archivo Zaragoza Antigua" (GAZA).', 1962, 1962, 1962, 'Anos 60', 'SAN JOS‚Ēú√ę', 41.63792300, -0.88297100, '0101000020E610000014200A664C41ECBFE02EFB75A7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33215518083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33215518083.webp', 'https://www.flickr.com/photos/zaragozaantigua/33215518083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22235, 'Romareda c.1955', 'Singular imagen capturada desde el nuevo Seminario Mayor o Metropolitano de Zaragoza y centrada en el panorama que desde all‚Ēú¬° se ten‚Ēú¬°a de la tradicional zona agr‚Ēú¬°cola del t‚Ēú¬ģrmino de la Romareda. Se destaca al fondo la mole de la Residencia Sanitaria Jose Antonio, inmediata al convento de Jerusal‚Ēú¬ģn. A la izquierda, torre de la Feria Nacional de Muestras y torre de la Editorial Luis Vives. A la derecha, el Colegio-Residencia de Nuestra Se‚Ēú‚Ėíora del Pilar para Hu‚Ēú¬ģrfanos e Hijos del Magisterio.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63643800, -0.90444000, '0101000020E61000003737A6272CF1ECBF40F7E5CC76D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50234103647.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50234103647.webp', 'https://www.flickr.com/photos/zaragozaantigua/50234103647/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22475, 'Marqu‚Ēú¬ģs de Ahumada 1962', 'Irrepetible captura visual desde la terraza del n‚Ē¨‚ēĎ 14 de la calle del Marqu‚Ēú¬ģs de Ahumada, en el antiguo barrrio de los "Chiflaos", con una panor‚Ēú√≠mica perdida en la dimensi‚Ēú‚Ēān del pasado, que culmina al fondo con las estilizadas torres del Pilar. Inmediatos al objetivo, los tejados de las antiguas parcelas n‚Ē¨‚ēĎ 11 y n‚Ē¨‚ēĎ 13 de la referida calle; detr‚Ēú√≠s, el n‚Ē¨‚ēĎ 18 de la calle Francisco Cid‚Ēú‚Ēān, y el n‚Ē¨‚ēĎ 44 de la calle General Mill‚Ēú√≠n Astray, ambas recayentes a la plaza hom‚Ēú‚Ēānima. A la derecha, y al fondo, el referencial dep‚Ēú‚Ēāsito del "Gas" en el camino de las Torres, y a la izquierda, la mole del colegio de los PP. Agustinos. Con el tiempo, la foresta que emerge de las parcelas ser‚Ēú√≠ progresivamente sustituida, junto a estas, por construcciones m‚Ēú√≠s modernas, y compactadas. Fuente visual: exclusiva aportaci‚Ēú‚Ēān de la colecci‚Ēú‚Ēān de Vicente Garc‚Ēú¬ģs al "Gran Archivo Zaragoza Antigua" (GAZA).', 1962, 1962, 1962, 'Anos 60', 'SAN JOS‚Ēú√ę', 41.63809100, -0.88271300, '0101000020E6100000292158552F3FECBF9C6F44F7ACD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33861200272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33861200272.webp', 'https://www.flickr.com/photos/zaragozaantigua/33861200272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22752, 'Av. del Tenor Fleta 1971', 'Imagen de la avenida del Tenor Fleta en su primer tramo entre el paseo del General Mola (al fondo), y el cruce con el camino de las Torres (donde el reciente y chaflanero n‚Ē¨‚ēĎ 98 de este camino, inmediato y a la derecha). Al fondo, perdura el inmueble esquinero del paseo del General Mola con la avenida de Goya, en esos momentos funcionando todav‚Ēú¬°a como academia La Figuera, si bien poco le quedaba de porvenir. El provinciano edificio del antiguo n‚Ē¨‚ēĎ 17, casi en el centro de la imagen, destaca por una pertinaz escualidez que lo hace casi invisible entre los modernos gigantes que lo flanquean, un mal edilicio de remedio afortunadamente subsanable, al tiempo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.64136300, -0.88429000, '0101000020E610000040C1C58A1A4CECBFA6EECA2E18D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32636126460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32636126460.webp', 'https://www.flickr.com/photos/zaragozaantigua/32636126460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22910, 'Front‚Ēú‚Ēān agustino 1985', 'Imagen del antiguo front‚Ēú‚Ēān doble del gran colegio de los PP. Agustinos, levantado en los a‚Ēú‚Ėíos 30 del pasado siglo. En el momento de realizar esta captura, una zona del original per‚Ēú¬°metro (al sureste) ya hab‚Ēú¬°a sido retranqueada unas decenas de metros durante la urbanizaci‚Ēú‚Ēān del pol‚Ēú¬°gono de Miraflores, y apertura de nuevos viales (calle de Uncastillo, y paseo de los Rosales). A la derecha del front‚Ēú‚Ēān perduraba una arboleda, y una gran zona de huerta y campos de cultivo, y al fondo, un campo de f‚Ēú‚ēĎtbol, de los dos que lleg‚Ēú‚Ēā a haber (entre ellos, el de "La Amistad"). Tras los muros del colegio, las grandes torres de viviendas del pol‚Ēú¬°gono de Miraflores, el colegio p‚Ēú‚ēĎblico Miraflores, el parque del mismo nombre, y algunos grandes bloques de la avenida de Ces‚Ēú√≠reo Alierta, en el emboque a la calle del escultor F‚Ēú¬ģlix Burriel. Unos pocos a‚Ēú‚Ėíos despu‚Ēú¬ģs, la mayor parte de este sector del colegio desaparecer‚Ēú√≠ tras la venta del suelo, la construcci‚Ēú‚Ēān de dos grandes bloques en el andador de Luis Puntes, y la apertura de la nueva calle de Francisco Albi‚Ēú‚Ėíana, que pasar‚Ēú√≠ justo por donde est‚Ēú√≠ el front‚Ēú‚Ēān (a menos cota de altura). Fuente visual: www.agustinoszaragoza.com/', 1985, 1985, 1985, 'Anos 80', 'SAN JOS‚Ēú√ę', 41.64085800, -0.88079300, '0101000020E61000009B7631CD742FECBFA3B08BA207D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22823346958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22823346958.webp', 'https://www.flickr.com/photos/zaragozaantigua/22823346958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23257, 'C.‚Ē¨‚ēĎ de las Torres 1968', 'Imagen capturada durante las obras de urbanizaci‚Ēú‚Ēān de la avenida de Tenor Fleta desde el paseo del General Mola, a la derecha, y hasta el camino del Puente del Virrey, hacia la izquierda. Esta actuaci‚Ēú‚Ēān estaba relacionada con el cubrimiento de la zanja del ferrocarril desde Campo Sepulcro, que impuls‚Ēú‚Ēā el vertiginoso y vertical crecimiento de bloques habitacionales a ambos lados del antiguo "camino del ferrocarril de los directos Madrid-Barcelona", ahora redenominado en estos casi cuatro kil‚Ēú‚Ēāmetros como "Goya", y "Tenor Fleta". Esta imagen se ha tomado en el cruce de Tenor Fleta con el camino de las Torres, que al fondo confluye con General Mola. La macizada manzana de bloques en construcci‚Ēú‚Ēān de la izquierda fue durante muchas d‚Ēú¬ģcadas la ubicaci‚Ēú‚Ēān de las instalaciones de la TUDOR. Podemos contemplarla tan di‚Ēú√≠fanamente porque los nuevos bloques de Tenor Fleta a‚Ēú‚ēĎn no han llegado a ese punto. A la derecha, la esquinera ubicaci‚Ēú‚Ēān de la cl‚Ēú¬°nica del doctor Ricardo Horno inaugurada en 1950. En primer t‚Ēú¬ģrmino, la acequia de las Adulas, o del Presidio, o de San Jos‚Ēú¬ģ, fluyendo al aire en direcci‚Ēú‚Ēān al salto de la "Lanera Aragonesa", primero, y al "Gas", despu‚Ēú¬ģs.', 1968, 1968, 1968, 'Anos 60', 'SAN JOS‚Ēú√ę', 41.64112200, -0.88381800, '0101000020E610000052B7B3AF3C48ECBF815F234910D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22489447334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22489447334.webp', 'https://www.flickr.com/photos/zaragozaantigua/22489447334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24188, 'Tenor Fleta 1951', 'Imagen de la calle Tenor Fleta desde el cruce con el Camino de las Torres, en direcci‚Ēú‚Ēān a Puente Virrey, al fondo. A la izquierda, el muro de los PP. Agustinos. A la derecha, campos de cultivo entre el Camino de las Alcachoferas y la Torre de Fletas. Fuente visual: Archivo Mora, AMZ.', 1951, 1951, 1951, 'Anos 50', 'SAN JOS‚Ēú√ę', 41.64047900, -0.88270400, '0101000020E61000005D8C81751C3FECBF2C634337FBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20325813261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20325813261.webp', 'https://www.flickr.com/photos/zaragozaantigua/20325813261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25018, 'Disco Bar &quot;Liverpool&quot; 1977', 'Colectivo Pl‚Ēú√≠stico de Zaragoza. Octubre 1977. En el chafl‚Ēú√≠n de la calle Com‚Ēú¬°n con el Camino de las Torres, "Liverpool discotheque", "La Liverpul", de cuando en las discotecas se pon‚Ēú¬°a m‚Ēú‚ēĎsica rock. La fachada, un mural ideado y realizado por el "Colectivo Pl‚Ēú√≠stico de Zaragoza".', 1977, 1977, 1977, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.64148900, -0.88359400, '0101000020E61000006C239EEC6646ECBF33DFC14F1CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15007121087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15007121087.webp', 'https://www.flickr.com/photos/zaragozaantigua/15007121087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25773, 'C.‚Ē¨‚ēĎ de las Torres 1968', 'Imagen capturada durante el proceso de urbanizaci‚Ēú‚Ēān de la avenida del Tenor Fleta, en el cruce con el camino de las Torres, con la caudalosa y antigua acequia de las Adulas, o de San Jos‚Ēú¬ģ, como protagonista en primer plano, tras recibir el aporte de la acequia del Entonar, desde el antiguo camino de las Alcachoferas, por la derecha. A la izquierda, vista muy parcial del nuevo bloque del n‚Ē¨‚ēĎ 19 de la avenida del Tenor Fleta, levantado sobre el huerto trasero del n‚Ē¨‚ēĎ 18-20 de la calle Com‚Ēú¬°n, antigua del Alba. A su derecha, huertos de las parcelas de los antiguos n‚Ē¨‚ēĎ 22, y 24 de esa misma calle, que poco despu‚Ēú¬ģs ser‚Ēú¬°an sustituidas por un bloque con el nuevo n‚Ē¨‚ēĎ 98-100 del camino de las Torres. Tras ellas, emergen las obras de construcci‚Ēú‚Ēān del nuevo bloque del n‚Ē¨‚ēĎ 96, recayente a la calle de Com‚Ēú¬°n. A la izquierda, el convento-colegio de los PP. Agustinos, y la gr‚Ēú‚ēĎa de obra de la nueva iglesia parroquial de Santa Rita de Casia. Fuente visual: Archivo Municipal de Zaragoza.', 1968, 1968, 1968, 'Anos 60', 'SAN JOS‚Ēú√ę', 41.64096200, -0.88411900, '0101000020E61000000FB6D8EDB34AECBF48FDF50A0BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33631770375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33631770375.webp', 'https://www.flickr.com/photos/zaragozaantigua/33631770375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25786, 'C.‚Ē¨‚ēĎ de las Torres 1968', 'Imagen capturada durante las obras de cubrimiento de la acequia de San Jos‚Ēú¬ģ previas a la urbanizaci‚Ēú‚Ēān del tramo del camino de las Torres comprendido entre la calle de Col‚Ēú‚Ēān (a la izquierda) y del Tenor Fleta. De fondo, los modernos inmuebles de los n‚Ēú‚ēĎmeros 106 y 104 del camino de las Torres, por donde circula entre el tr‚Ēú√≠fico un autob‚Ēú‚ēĎs de la l‚Ēú¬°nea "Puente Virrey-Plaza de Huesca". En primer t‚Ēú¬ģrmino, zanja de la acequia de las Adulas, del Presidio (porque pasaba junto al antiguo presidio o penal), o de San Jos‚Ēú¬ģ durante las obras de cubrimiento a la altura de las calles de N.‚Ē¨¬¨ S.‚Ē¨¬¨ de Abarca y Jos‚Ēú¬ģ Pellicer.', 1968, 1968, 1968, 'Anos 60', 'SAN JOS‚Ēú√ę', 41.64075900, -0.88435600, '0101000020E61000001DAF40F4A44CECBF10CF126404D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51658962504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51658962504.webp', 'https://www.flickr.com/photos/zaragozaantigua/51658962504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25994, 'PP. Agustinos A‚Ēú‚Ėíos 40', 'Imagen que a‚Ēú‚ēĎn sigue catalogada oficialmente como "La Zaragozana. F‚Ēú√≠brica de cerveza. Vista exterior de la f‚Ēú√≠brica." Se trata del convento-colegio de los PP. Agustinos en el Camino de las Torres, tomada desde la trasera del pabell‚Ēú‚Ēān principal, con una buena visual del terreno de Miraflores que, delimitado por su muralla neomud‚Ēú¬ģjar, formaba parte del colegio. Construido en estilo historicista-ecl‚Ēú¬ģctico seg‚Ēú‚ēĎn proyecto de Miguel ‚Ēú√ľngel Navarro al comienzo de los a‚Ēú‚Ėíos 30, contaba en proyecto con una enorme iglesia cuya torre alcanzaba los 70 metros de altura. Tras el 18-07-1936, los nacionalistas lo reutilizaron como cuartel y hospital de aliados italianos, y las obras quedaron suspensas. Tras 1939, la original iglesia ya no se realizar‚Ēú¬°a. En la imagen se aprecia la traza de su proyectada planta en cruz latina con naves laterales abiertas en capillas. En 1968 comenzaron las obras de una nueva iglesia seg‚Ēú‚ēĎn planos de Jos‚Ēú¬ģ Luis Navarro (hijo de Miguel ‚Ēú√ľngel Navarro). El proyecto, menos costoso, sin la torre, y en otro estilo, fue consagrado a la santa cat‚Ēú‚Ēālica "abogada de los imposibles" (santa Rita de Casia), que tambi‚Ēú¬ģn lo es de las v‚Ēú¬°ctimas de abusos, personas en soledad, de la prevenci‚Ēú‚Ēān de esterilidad y enfermedades del cuerpo en general, de matrimonios con dificultades, viudas, padres... Fuente visual: AHPZ, Archivo Mora', 1940, 1940, 1949, 'Anos 40', 'SAN JOS‚Ēú√ę', 41.64140900, -0.88128800, '0101000020E6100000936E4BE48233ECBF172EABB019D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20357950342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20357950342.webp', 'https://www.flickr.com/photos/zaragozaantigua/20357950342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25765, 'Av. San Jos‚Ēú¬ģ 1977', 'Imagen capturada en el tramo alto de la avenida de San Jos‚Ēú¬ģ, entre las calles de Garc‚Ēú¬°a Lorca y Luis Royo Villanova (ambas, a la derecha), con visual (a la izquierda) de la fachada del "Colegio de Mar‚Ēú¬°a Auxiliadora" de las salesianas, inaugurado en 1953, y del solar dejado por las antiguas parcelitas de los n‚Ēú‚ēĎmeros 206 y 208, donde poco despu‚Ēú¬ģs se levantar‚Ēú√≠ el actual bloque 206-208. Junto al colegio, a su izquierda, una peque‚Ēú‚Ėía puertecilla (que perdura) indica el cauce al aire de la acequia del Entonar, que baja desde la antigua f‚Ēú√≠brica textil de PINASAR. La conversi‚Ēú‚Ēān del antiguo camino de San Jos‚Ēú¬ģ en una gran v‚Ēú¬°a de circulaci‚Ēú‚Ēān rodada, que pasa circunstancialmente por el barrio de San Jos‚Ēú¬ģ, es un hito de la movilidad urbana que deber‚Ēú¬°a ser revertido. El retorno del tranv‚Ēú¬°a en su versi‚Ēú‚Ēān moderna es, en este sentido, una posibilidad para un futuro mejor. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.63527700, -0.87992400, '0101000020E610000069E55E605628ECBF5473B9C150D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32675506530.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32675506530.webp', 'https://www.flickr.com/photos/zaragozaantigua/32675506530/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25779, 'Calle de Agust‚Ēú¬°n Querol c.1945', 'Imagen capturada desde un bald‚Ēú¬°o inmediato a la acequia del Ontonar (a la derecha, fuera de plano) y centrada en la cara sur de la f‚Ēú√≠brica de cerveza, malta y hielo La Zaragozana SA con sus originales instalaciones y gran chimenea de principios de siglo dise‚Ēú‚Ėíadas por los ingenieros Mayand‚Ēú¬°a y Egozcue (Egorg‚Ēú‚ēĚe o Ezorg‚Ēú‚ēĚe, seg‚Ēú‚ēĎn otras versiones). A la izquierda, traseras de la parcela con extenso huerto del n‚Ē¨‚ēĎ 1 de la desaparecida calle de Agust‚Ēú¬°n Querol. Apilados junto al muro, centenares de cascos de vidrio posiblemente usados y algunas cajas de madera para botellas. Detr‚Ēú√≠s de la f‚Ēú√≠brica, el camino de las Alcachoferas, por donde fluye en paralelo la acequia de Ontonar hasta desembocar en la acequia de San Jos‚Ēú¬ģ en el camino de las Torres. A‚Ēú‚Ėíos despu‚Ēú¬ģs comenz‚Ēú‚Ēā la radical remodelaci‚Ēú‚Ēān urban‚Ēú¬°stica de este entorno, impulsada fundamentalmente por la ampliaci‚Ēú‚Ēān edilicia de la f‚Ēú√≠brica cervecera. Fuente visual: foto Juan Mora Insa, en Archivo Jos‚Ēú¬ģ Mar‚Ēú¬°a Ballest‚Ēú¬°n Miguel.', 1945, 1945, 1945, 'Anos 40', 'SAN JOS‚Ēú√ę', 41.63663200, -0.88136100, '0101000020E61000000F09DFFB1B34ECBF25CB49287DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40568194804.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40568194804.webp', 'https://www.flickr.com/photos/zaragozaantigua/40568194804/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21540, '&quot;Jard‚Ēú¬°n de Pina&quot; 1923', 'La impresionante casa de D‚Ēú√≠maso Pina llamaba la atenci‚Ēú‚Ēān en las terrazas de Pina, junto al Canal Imperial, en las alturas del barrio de San Jos‚Ēú¬ģ, en una curva que tantas veces aparece en postales, fotograf‚Ēú¬°as e im‚Ēú√≠genes de la ‚Ēú¬ģpoca. Mas esa no era la ‚Ēú‚ēĎnica cosa rese‚Ēú‚Ėíable de esta notable construcci‚Ēú‚Ēān. Detr‚Ēú√≠s de la fachada y su visual remate en torre‚Ēú‚Ēān, aguardaba un precioso conjunto de jardines, estatuas, p‚Ēú¬ģrgolas, parterres, un cenador, y una destacable variedad de plantas y ‚Ēú√≠rboles con buenas vistas a los terrenos inferiores, y al propio Canal, desde donde flu‚Ēú¬°a la acequia del Ontonar. Los importantes desniveles aterrazados, m‚Ēú√≠s all‚Ēú√≠ de los muros de la casa, permit‚Ēú¬°an ocho fruct‚Ēú¬°feros huertos de notable tama‚Ēú‚Ėío. La imagen recoge la parte del jard‚Ēú¬°n orientada hacia la calle de Cantarranas y, m‚Ēú√≠s abajo, la f‚Ēú√≠brica textil de la misma familia Pina, de la que un pedazo de chimenea destaca por encima de la balaustrada. A la izquierda de estos jardines un a‚Ēú‚Ėío despu‚Ēú¬ģs se instalar‚Ēú√≠ el colegio de La Salle Torrero, para hacer competencia a las cercanas y laicas escuelas de Julio Cejador Frauca. As‚Ēú¬° se mantuvo esto hasta la d‚Ēú¬ģcada de los a‚Ēú‚Ėíos 70, cuando toda la superficie de la casa, el jard‚Ēú¬°n y los huertos, fueron aplanados y reconvertidos en los bloques de viviendas que hoy se elevan entre las calles del Pintor Mar‚Ēú¬°n Bag‚Ēú‚ēĚ‚Ēú¬ģs, la Plaza del Canal Imperial, y las Terrazas de Cu‚Ēú¬ģllar. Fuente visual: AHPZ. Archivo Julio Requejo. 10/06/1923.', 1923, 1923, 1923, 'Anos 20', 'SAN JOS‚Ēú√ę', 41.63285300, -0.87960300, '0101000020E6100000E5D4CE30B525ECBF7616BD5301D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20043777129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20043777129.webp', 'https://www.flickr.com/photos/zaragozaantigua/20043777129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21541, 'F‚Ēú√≠brica de Pina 1927', 'Zaragoza tuvo que esperar hasta bien mediados del XIX para que se iniciara a escala apreciable la fabricaci‚Ēú‚Ēān mec‚Ēú√≠nica de tejidos, principalmente de lencer‚Ēú¬°a, lonas, y algunas telas de vestir. Mientras que las telas de vestir seguir‚Ēú√≠n siendo importadas al 98%, el "boom" textil fue protagonizado por la fabricaci‚Ēú‚Ēān de lonas para alpargatas, para toldos, velamen de embarcaciones, y otros usos, de tal forma que Zaragoza se convirti‚Ēú‚Ēā en suministrador principal del mercado interior espa‚Ēú‚Ėíol. Uno de los promotores industriosos m‚Ēú√≠s destacados fue D‚Ēú√≠maso Pina (padre), que tuvo continuidad familiar con sus hijos, D‚Ēú√≠maso Pina (hijo), y aun nietos, Alfredo Sarto Pina, con quienes la f‚Ēú√≠brica lleg‚Ēú‚Ēā a ser una de las m‚Ēú√≠s importantes de Espa‚Ēú‚Ėía. La factor‚Ēú¬°a principal estaba ubicada en lo que hoy es el Parque-Jard‚Ēú¬°n de la Memoria del Barrio, que la imagen captura desde los feraces campos de labor de la actual calle Melilla. La imagen de conjunto es ciertamente impresionante, y en el interior de las naves se contaba con la maquinaria textil m‚Ēú√≠s moderna del momento, como la m‚Ēú√≠quina "rompe-balsa"; la Caja de polvo Grigthon con su abridora y transportador; un Bat‚Ēú√≠n atelador; un Bat‚Ēú√≠n repasador; Cardas de chaprones; m‚Ēú√≠quinas de estirar y torcer las mechas; m‚Ēú√≠quinas mecheras; m‚Ēú√≠quinas continuas de hilar; m‚Ēú√≠quinas de retorcer; m‚Ēú√≠quina de doblar, de aspeas, de hacer cordones especiales, etc. Hab‚Ēú¬°a tambi‚Ēú¬ģn instalaciones para blanqueo, apresto y te‚Ēú‚Ėíido de hilados. La lona sal‚Ēú¬°a para hacer alpargatas, para toldos de vagones de tren y todo tipo de carruajes, para mangueras, para filtros de azucareras, loneta kaki para uniformes, para calzados, para cinchas de caballer‚Ēú¬°as... En total, unos 50.000 metros cuadrados, y m‚Ēú√≠s de 500 personas trabajando en las instalaciones. Fuese, y no hubo nada, ni siquiera la chimenea de la imagen, que se intent‚Ēú‚Ēā mantener como recuerdo y memoria del Barrio y la ciudad, pero eran a‚Ēú‚Ėíos en que la moda de la conservaci‚Ēú‚Ēān de chimeneas no estaba muy asentada. Fuente visual: ', 1927, 1927, 1927, 'Anos 20', 'SAN JOS‚Ēú√ę', 41.63409600, -0.87890600, '0101000020E6100000FA42C879FF1FECBF2043C70E2AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20062892550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20062892550.webp', 'https://www.flickr.com/photos/zaragozaantigua/20062892550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21618, 'Calle de Cantarranas 1926', 'Imagen de la maqueta con las instalaciones de la f‚Ēú√≠brica de tejidos Hijos de D‚Ēú√≠maso Pina, S.A., en la empinada parte final del camino de San Jos‚Ēú¬ģ donde la abundancia de agua surtida del Canal Imperial por medio de las acequias del Plano, y de Ontonar, convirti‚Ēú‚Ēā a esta zona en el principio del siglo XX en un denso paraje industrial con las harineras de La Constancia, y de Mor‚Ēú‚Ēān, una f‚Ēú√≠brica de yeso, y este monumental taller textil. A la izquierda de la maqueta, la fila de viviendas para trabajadores de la f‚Ēú√≠brica construidas en la calle de Cantarranas (el ‚Ēú‚ēĎnico vial con nombre, en esa ‚Ēú¬ģpoca), y cuyas traseras daban a la referencial Torre de D‚Ēú√≠maso Pina. Luego, y en descenso, sucesi‚Ēú‚Ēān de naves y talleres junto a la derivaci‚Ēú‚Ēān de la acequia del Ontonar que era conducida por el interior de la f‚Ēú√≠brica. En primer plano, el edificio con el taller de reparaciones de maquinaria, la carpinter‚Ēú¬°a, y un almac‚Ēú¬ģn. Tras el cierre y derribo de la factor‚Ēú¬°a, este terreno fue encaminado por los senderos de la especulaci‚Ēú‚Ēān urban‚Ēú¬°stica (que no es un defecto, sino la definici‚Ēú‚Ēān del proceso) hacia la conversi‚Ēú‚Ēān en un conglomerado de torres edilicias babil‚Ēú‚Ēānicas, de las que afortunadamente s‚Ēú‚Ēālo se hizo una. La chimenea fue el ‚Ēú‚ēĎltimo vestigio de esta f‚Ēú√≠brica que qued‚Ēú‚Ēā en pie durante unos a‚Ēú‚Ėíos, y que la asociaci‚Ēú‚Ēān vecinal de San Jos‚Ēú¬ģ trabaj‚Ēú‚Ēā para su permanencia, mas no fue posible (el Ayuntamiento no quiso). Fuente visual: La Historia de la Industrializaci‚Ēú‚Ēān de Zaragoza.', 1926, 1926, 1926, 'Anos 20', 'SAN JOS‚Ēú√ę', 41.63409600, -0.87890600, '0101000020E6100000FA42C879FF1FECBF2043C70E2AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32270418835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32270418835.webp', 'https://www.flickr.com/photos/zaragozaantigua/32270418835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21654, 'Calle del Doce de Octubre 1927', 'Imagen centrada en el primer tramo de la calle del Doce de Octubre capturada desde su arranque en el camino de San Jos‚Ēú¬ģ. A la izquierda e inmediatos, talleres de la f‚Ēú√≠brica de muebles de Urbano Bernardos de Frutos. A la derecha, parcelas con viviendas de dos alturas del lado de los pares de esta calle, en cuyas traseras se abr‚Ēú¬°an los correspondientes huertos regados por una derivada de la acequia del Antonar o Entonar. El firme de terroso, destacando alguna espor‚Ēú√≠dica pareja de ‚Ēú√≠rboles donde "la acera". Hacia el fondo la calle se va empinando en su ascenso a las calles de Lizarbe. Tejar, y al barrio de Cuber.', 1927, 1927, 1927, 'Anos 20', 'SAN JOS‚Ēú√ę', 41.63585400, -0.87875400, '0101000020E61000007A5567B5C01EECBFF183F3A963D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52195393221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52195393221.webp', 'https://www.flickr.com/photos/zaragozaantigua/52195393221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21656, 'Calle de la Huerta 1927', 'Imagen capturada en el barrio de Col‚Ēú‚Ēān, tramo final y en ascenso de la calle de la Huerta donde al fondo arranca hacia la derecha la calle de Levante. Era este uno de los barrios particulares surgidos de la parcelaci‚Ēú‚Ēān de varios terrenos de cuatro grandes propietarios en esta empinada zona inmediata al Canal Imperial de Arag‚Ēú‚Ēān. En el momento de realizar esta fotograf‚Ēú¬°a se encontraba vertebrado por las calles de Am‚Ēú¬ģrica, Treinta y Uno de Julio, Zaragoza, Nador, La Huerta y Levante, y contaba con unas ciento treinta parcelas (construidas y en construcci‚Ēú‚Ēān) de una/dos alturas con huerto y corral. Su condici‚Ēú‚Ēān de barrio particular lo asemejaba a los otros barrios particulares de la zona y de la ciudad en general: sin pavimentaci‚Ēú‚Ēān, iluminaci‚Ēú‚Ēān, agua corriente y vertido de aguas residuales, entre otros servicios b‚Ēú√≠sicos de los que carec‚Ēú¬°a. Esas "cualidades" se traduc‚Ēú¬°an en que sus moradores fueran familias trabajadoras pobres o muy pobres.', 1927, 1927, 1927, 'Anos 20', 'SAN JOS‚Ēú√ę', 41.63181900, -0.87670600, '0101000020E61000008C9FC6BDF90DECBFE7FEEA71DFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52326513929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52326513929.webp', 'https://www.flickr.com/photos/zaragozaantigua/52326513929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21680, 'San Jos‚Ēú¬ģ-Cuber-Col‚Ēú‚Ēān 1932', 'Imagen capturada desde la quinta del industrial Leandro Sanz P‚Ēú¬ģrez, inmediata a la f‚Ēú√≠brica de lonas para alpargatas de su propiedad en el n‚Ē¨‚ēĎ 376 de Torrero, desde que se separara de su socio el se‚Ēú‚Ėíor Castillo en 1902 y que desde 1930 era denominada "F‚Ēú√≠brica de Tejidos de los Hijos de don Leandro Sanz", situada a la izquierda y fuera de plano en esta elevada zona entre la traves‚Ēú¬°a del Puente del Virrey y la calle de Cuber. Entre la torre, quinta o casa y la f‚Ēú√≠brica y al aire fluye la nueva acequia del Plano, que aqu‚Ēú¬° ten‚Ēú¬°a un salto de agua para proveer de energ‚Ēú¬°a a la f‚Ēú√≠brica y que en la imagen se muestra encajonada y en serpenteante descenso desde la altura de la f‚Ēú√≠brica textil de D‚Ēú√≠maso Pina. Hacia el fondo, el final en alto de la calle del Doce de Octubre y el arranque de la subida de Besc‚Ēú‚Ēās, donde el barrio de San Jos‚Ēú¬ģ lindaba con el barrio de Cuber y la torre de don Felipe Cuber. Detr‚Ēú√≠s, el urbanismo disperso y discontinuo llega, en ascenso, hasta las parcelas del barrio de Col‚Ēú‚Ēān que coronan su altura determinada a la derecha por la calle de los M‚Ēú√≠rtires de Jaca y su confluencia con la calle de Am‚Ēú¬ģrica. El escenario aparece decorado de blanco por la destacada nevada que la ma‚Ēú‚Ėíana del d‚Ēú¬°a 12 de febrero de ese a‚Ēú‚Ėío deposit‚Ēú‚Ēā espesores entre los 20 y 40 cent‚Ēú¬°metros. que en las "afueras" despert‚Ēú‚Ēā gran expectaci‚Ēú‚Ēān entre el vecindario, originando adem‚Ēú√≠s una "peregrinaci‚Ēú‚Ēān" de zaragozanos que desde la ciudad sub‚Ēú¬°an hasta las alturas del Cabezo y parque de Buenavista, adem‚Ēú√≠s del Cabezo Cortado, que en la imagen queda fuera de plano y bastante a la izquierda.', 1932, 1932, 1932, 'Anos 30', 'SAN JOS‚Ēú√ę', 41.63470600, -0.87635200, '0101000020E61000001A187959130BECBF9949D40B3ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877621231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877621231.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877621231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22099, 'Avenida de San Jos‚Ēú¬ģ 1951', 'La unidad 92, de la l‚Ēú¬°nea 13 ("San Jos‚Ēú¬ģ"), delante del reciente cine Rialto (hab‚Ēú¬°a abierto un par de a‚Ēú‚Ėíos antes), donde la Cuesta de Mor‚Ēú‚Ēān se hace carne mortal y nos recuerda que "subir" a Torrero no es una met‚Ēú√≠fora. El tranv‚Ēú¬°a, seg‚Ēú‚ēĎn los expertos, estaba pintado en azul y crema, y este publicita un producto "repara medias". A la izquierda, la entrada a la calle Doce de Octubre, flanqueada por una parcela con peluquer‚Ēú¬°a en los bajos, y por las naves de la "Catedral del Mueble". Fuente visual: Los tranv‚Ēú¬°as de Zaragoza, J. Pe‚Ēú‚Ėía - J. M. Valero, DPZ, 1985.', 1951, 1951, 1951, 'Anos 50', 'SAN JOS‚Ēú√ę', 41.63574000, -0.87912000, '0101000020E6100000FD4D2844C021ECBF2861A6ED5FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20392959372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20392959372.webp', 'https://www.flickr.com/photos/zaragozaantigua/20392959372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22171, 'Av. San Jos‚Ēú¬ģ c.1956', 'Luminosa y festiva captura realizada junto a la marquesina del original cine Rialto, inaugurado unos a‚Ēú‚Ėíos antes en la avenida de San Jos‚Ēú¬ģ, en el arranque de la "Cuesta de Mor‚Ēú‚Ēān", cuya reconocida dureza fue reconocida en eventos como este: una competici‚Ēú‚Ēān ciclista amateur con todas las de la ley, organizada en esta humilde barriada de la periferia. La imagen recoge el momento de entrega de distinciones a los ganadores (o supervivientes), junto a la tribuna repleta de p‚Ēú‚ēĎblico que posa con entusiasmo, mientras un locutor, a la derecha, anima el evento. En primer t‚Ēú¬ģrmino, Antonio Mari‚Ēú‚Ėíosa Gea, Adolfo Bello y posiblemente Jos‚Ēú¬ģ Gasc‚Ēú‚Ēān. Fuente visual: Banco de Im‚Ēú√≠genes del Barrio de San Jos‚Ēú¬ģ.', 1956, 1956, 1956, 'Anos 50', 'SAN JOS‚Ēú√ę', 41.63574000, -0.87912000, '0101000020E6100000FD4D2844C021ECBF2861A6ED5FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31365402064.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31365402064.webp', 'https://www.flickr.com/photos/zaragozaantigua/31365402064/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22518, 'C.‚Ē¨‚ēĎ del Puente del Virrey c.1964', 'In‚Ēú¬ģdita imagen capturada en la torre de Alfredo Sarto Pina sita en el camino del Puente del Virrey donde figura Carmen L‚Ēú√≠zaro Sierra, hija de los "guardeses" de la torre. Al fondo y sobre el muro de la torre, una oriental y despejada vista que alcanza hasta la manzana de modernas viviendas (incluyendo un desarrolista bloque de nueve alturas) construidas en el ‚Ēú‚ēĎltimo tramo de la calle de Cartagena, entre una calle de nueva traza que poco despu‚Ēú¬ģs ser‚Ēú¬°a denominada de Armando Palacio Vald‚Ēú¬ģs y el camino de Cabald‚Ēú‚Ēās. Poco despu‚Ēú¬ģs de ser tomada esta fotograf‚Ēú¬°a la torre de Alfredo Sarto Pina completar‚Ēú¬°a su urbanizaci‚Ēú‚Ēān de la que resultar‚Ēú¬°a la apertura de la actual calle de ‚Ēú√ľngel Ganivet y la construcci‚Ēú‚Ēān de los bloques del lado de sus impares.', 1964, 1964, 1964, 'Anos 60', 'SAN JOS‚Ēú√ę', 41.63844200, -0.87447500, '0101000020E61000005D6DC5FEB2FBEBBF4832AB77B8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52488699499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52488699499.webp', 'https://www.flickr.com/photos/zaragozaantigua/52488699499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22521, 'Traves‚Ēú¬°a del Puente del Virrey 1961', 'Imagen capturada durante las fiestas del barrio de San Jos‚Ēú¬ģ del a‚Ēú‚Ėío 1961 organizadas en honor de San Jos‚Ēú¬ģ de Calasanz, durante la procesi‚Ēú‚Ēān general que tras el rezo del rosario en la iglesia de San Lino recorri‚Ēú‚Ēā algunas calles de la parte alta del barrio. Aqu‚Ēú¬° la procesi‚Ēú‚Ēān viene de bajada desde la calle de Lizarbe desembocando en la arbolada Traves‚Ēú¬°a del Puente del Virrey para continuar luego por la calle de Zaragoza la Vieja y el camino del Puente del Virrey hasta la avenida del Tenor Fleta. La escena se centra en las "bell‚Ēú¬°simas" se‚Ēú‚Ėíoritas ataviadas con festivos atuendos, tradicionalistas mantillas y las bandas que las identifican como "presidentas" de las fiestas, acompa‚Ēú‚Ėíadas por un plantel de ni‚Ēú‚Ėías abaturradas y aspirantes a ser las "presidentas del ma‚Ēú‚Ėíana", por algunos escolapios y seguidas por los comunes.', 1961, 1961, 1961, 'Anos 60', 'SAN JOS‚Ēú√ę', 41.63618900, -0.87685700, '0101000020E6100000F6984869360FECBF988922A46ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54158959373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54158959373.webp', 'https://www.flickr.com/photos/zaragozaantigua/54158959373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22627, 'Av. de San Jos‚Ēú¬ģ 1974', 'Imagen de la unidad 208 de la tranviaria L‚Ēú¬°nea 11 (Parque-San Jos‚Ēú¬ģ) en la Avenida de San Jos‚Ēú¬ģ, tras haberse incorporado desde la izquierda, por la calle Suiza, y se dispone a iniciar el recorrido hasta el Parque. A la derecha, el acceso a la calle Bellavista, y vista de la antigua manzana de parcelas de los a‚Ēú‚Ėíos 30 que llegaba hasta la Traves‚Ēú¬°a del Puente del Virrey, con panader‚Ēú¬°a, tiendas de chuches y revistas, una vaquer‚Ēú¬°a, un taller... A‚Ēú‚Ėíos despu‚Ēú¬ģs, ser‚Ēú√≠n derribadas. Hoy, en ese lugar, se encuentra la nueva plaza del Primero de Mayo.', 1974, 1974, 1974, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.63630900, -0.87836900, '0101000020E6100000463F1A4E991BECBF4293C49272D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20151991458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20151991458.webp', 'https://www.flickr.com/photos/zaragozaantigua/20151991458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22631, 'Cadena de la Granja 1975', 'Son los ‚Ēú‚ēĎltimos d‚Ēú¬°as del a‚Ēú‚Ėío, un a‚Ēú‚Ėío que luego ser‚Ēú¬°a valorado como el principio de muchas cosas, incuestionables. Las permanencias y continuidades ocupar‚Ēú√≠n much‚Ēú¬°sima menos tinta: el pensamiento m‚Ēú√≠gico las tratar‚Ēú√≠ como si no estuvieran. Mas s‚Ēú¬°. As‚Ēú¬° terminaba entonces la flamante avenida del Tenor Fleta (al fondo) tras cruzarse con el Camino del Puente del Virrey. La imagen est‚Ēú√≠ capturada desde la terrenal calle "Cadena de la Granja", una de esas espl‚Ēú¬ģndidas, y perdidas, muestras del nomencl‚Ēú√≠tor zaragozano en llamar las cosas por su nombre, sin tener que apelar a extravagancias, como los juegos de computadora: aqu‚Ēú¬° hab‚Ēú¬°a una cadena para cerrar el paso a nivel que conduc‚Ēú¬°a a la Granja Agr‚Ēú¬°cola Experimental, antes del cubrimiento de la trinchera del tren. Un pretil pretend‚Ēú¬°a prevenir accidentes, aunque muy levemente. A la izquierda, el Colegio "Calixto Ari‚Ēú‚Ėío-Mariano de Cavia", una de las Escuelas construidas por la Segunda Rep‚Ēú‚ēĎblica que segu‚Ēú¬°an en las mismas condiciones, literalmente, que el d‚Ēú¬°a de su inauguraci‚Ēú‚Ēān. A la derecha, se atisba el comienzo de la desigual manzana que llegaba hasta la que fuera calle del "11 de febrero" (fecha de la proclamaci‚Ēú‚Ēān de la Primera Rep‚Ēú‚ēĎblica Espa‚Ēú‚Ėíola, en 1873), tras el 18 de julio de 1936 "Escultor Moreto". El paisaje lo domina la masa de gigantescos bloques de viviendas levantados durante el desarrollismo franquista, que se detuvo justo donde decidi‚Ēú‚Ēā terminar el cubrimiento de las v‚Ēú¬°as. M‚Ēú√≠s all‚Ēú√≠, es decir, m‚Ēú√≠s ac‚Ēú√≠, sin transici‚Ēú‚Ēān, el agro puro y duro. Los grandes propietarios de suelo hab‚Ēú¬°an decidido que la ciudad ten‚Ēú¬°a que crecer por otros lados. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.63642200, -0.87450700, '0101000020E610000035F0A31AF6FBEBBF3B3AAE4676D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20220875452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20220875452.webp', 'https://www.flickr.com/photos/zaragozaantigua/20220875452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22238, 'P‚Ē¨‚ēĎ Isabel la Cat‚Ēú‚Ēālica 1955', 'Nocturna imagen capturada desde la altura de la torre-mirador de la Feria de Muestras, orientada hacia el nuevo paseo de Isabel la Cat‚Ēú‚Ēālica, que iluminado vertebra esta perif‚Ēú¬ģrica zona de la ciudad, coincidente con el tranviario tendido de la l‚Ēú¬°nea 15. Casablanca. A su izquierda destaca la estructura de la Residencia Sanitaria Jos‚Ēú¬ģ Antonio y, m‚Ēú√≠s en penumbra, el Colegio-Residencia de Nuestra Se‚Ēú‚Ėíora del Pilar para Hu‚Ēú¬ģrfanos e Hijos del Magisterio. A la derecha, luces que alumbran los trabajos preliminares de la construcci‚Ēú‚Ēān del estadio municipal de f‚Ēú‚ēĎtbol, y a continuaci‚Ēú‚Ēān el convento de Jerusal‚Ēú¬ģn.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63565200, -0.90073900, '0101000020E6100000726A6798DAD2ECBF89D1730B5DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50878171236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50878171236.webp', 'https://www.flickr.com/photos/zaragozaantigua/50878171236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22637, 'Calle Suiza 1974', 'El 30 de agosto de 1945 se inaugura la L‚Ēú¬°nea 13 del tranv‚Ēú¬°a, denominada "San Jos‚Ēú¬ģ", de 2200 metros de longitud. Como la Plaza de Espa‚Ēú‚Ėía estaba saturada de terminales, se construy‚Ēú‚Ēā un ramal en la reci‚Ēú¬ģn ensanchada calle de Eusebio Blasco (lateral al Teatro Principal), para situar el comienzo de l‚Ēú¬°nea, cuya Terminal estaba al comienzo de la Cuesta de Mor‚Ēú‚Ēān, en la Avenida de S. Jos‚Ēú¬ģ, para dar servicio a la Harinera all‚Ēú¬° instalada. Poco despu‚Ēú¬ģs, justo all‚Ēú¬°, se inaugurar‚Ēú√≠ el Cine Rialto. En 1951 se construy‚Ēú‚Ēā un tortuoso bucle en la terminal de la Avenida de S. Jos‚Ēú¬ģ, zigzageando por las calles de "Mill‚Ēú√≠n Astray" (luego, Mar‚Ēú¬°a Moliner), Monforte y Suiza, para desembocar en la Avenida de S. Jos‚Ēú¬ģ. En 1967 se unieron las l‚Ēú¬°neas 11 y 13 en la nueva L‚Ēú¬°nea 11 "Parque-S. Jos‚Ēú¬ģ", en activo hasta el 23 de enero de 1976. En la imagen, captura de un veh‚Ēú¬°culo de la serie 200 saliendo de la calle Suiza para dar la pirivuelta que lo colocaba en disposici‚Ēú‚Ēān de acceder a la Avenida de S. Jos‚Ēú¬ģ para regresar hasta el "Parque". La parcela de la izquierda, con el n‚Ē¨‚ēĎ 176 de la Avenida, era de 1936, superviviente hasta hace no demasiado tiempo, en que fue derruida para ganar verticalidad. El edificio del otro lado de la calle, el n‚Ē¨‚ēĎ 172, de 1930 sobrevive, aunque ya sin la carnicer‚Ēú¬°a de la imagen. Fuente visual: Im‚Ēú√≠genes Antiguas Zaragoza.', 1974, 1974, 1974, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.63626100, -0.87886300, '0101000020E61000002843554CA51FECBF315C1D0071D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20258015861.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20258015861.webp', 'https://www.flickr.com/photos/zaragozaantigua/20258015861/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22775, 'Av. de San Jos‚Ēú¬ģ 1972', 'Imagen capturada en el cruce de la Av. del Tenor Fleta con la Av. de San Jos‚Ēú¬ģ, y motivada por el reciente retoque urban‚Ēú¬°stico que, al objeto de favorecer la movilidad del tr‚Ēú√≠nsito rodado, y siendo que la acera era demasiado espaciosa, hab‚Ēú¬°a alabeado lo que era una ortogonal esquina de toda la vida. El ‚Ēú‚ēĎnico problema, ahora, era que un poste esquinero hab‚Ēú¬°a sido dejado en su hist‚Ēú‚Ēārica ubicaci‚Ēú‚Ēān, de forma que el giro automovil‚Ēú¬°stico deb‚Ēú¬°a atenerse al del antiguo ‚Ēú√≠ngulo, para evitar el impacto. Como este giro era considerado vital para la circulaci‚Ēú‚Ēān rodada de la capital del Ebro, poco despu‚Ēú¬ģs el poste fue retranqueado, afortunadamente. A la izquierda de la imagen, la angulosa esquina del moderno bloque del n‚Ē¨‚ēĎ 95 de la Av. del Tenor Fleta, en cuyos bajos resplandec‚Ēú¬°a la sucursal de una caja de ahorro local inaugurada hac‚Ēú¬°a poco. Al fondo, tras el tr‚Ēú√≠nsito de la Av, de San Jos‚Ēú¬ģ, las provincianas construcciones recayentes al arranque de la calle de San Jos‚Ēú¬ģ de Calasanz, la de la izquierda inmediata al restaurante Fujiyama; la de la derecha, territorio de los ultramarinos Barriendo y sus antropol‚Ēú‚Ēāgicas pizarras de la fachada, donde se anunciaba el g‚Ēú¬ģnero a unos precios imbatibles. Tiempo despu‚Ēú¬ģs, esta esquina se convirti‚Ēú‚Ēā en moj‚Ēú‚Ēān administrativo referencial de la nueva ordenaci‚Ēú‚Ēān de la ciudad en distritos, ya que la zona de la izquierda de la imagen, delimitada por las avenidas de Tenor Fleta, San Jos‚Ēú¬ģ, y Ces‚Ēú√≠reo Alierta, fue adscrita al distrito Centro. Con esta rectificaci‚Ēú‚Ēān de fronteras, una zona hist‚Ēú‚Ēārica del perif‚Ēú¬ģrico barrio de San Jos‚Ēú¬ģ (antiguo callej‚Ēú‚Ēān de la Bailera, de Lobera, calle de Abad‚Ēú¬°a...) qued‚Ēú‚Ēā incluida en el exclusivo distrito Centro. Fuente visual: fotograf‚Ēú¬°a de Luis Mompel, en Heraldo de Arag‚Ēú‚Ēān.', 1972, 1972, 1972, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.63773900, -0.87687700, '0101000020E6100000BDAAB35A600FECBF1F317A6EA1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34334108764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34334108764.webp', 'https://www.flickr.com/photos/zaragozaantigua/34334108764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22777, 'Calle de Royo Villanova 1972', 'Imagen capturada entre las contrastadas zonas de sol y sombra del breve primer tramo de la calle de don Luis Royo Villanova, desde su arranque en la av. de San Jos‚Ēú¬ģ, al fondo. Este lugar era fil‚Ēú‚Ēān de sucesos por la persistencia al aire de la confluencia de la acequias del Plano, que tras pasar por la harinera SAPASA descend‚Ēú¬°a hacia la traves‚Ēú¬°a del Puente del Virrey; y de la acequia de Entonar/Ontonar, que tras pasar por la antigua f‚Ēú√≠brica textil de PINASAR cruzaba la av. de San Jos‚Ēú¬ģ y continuaba en direcci‚Ēú‚Ēān a la f‚Ēú√≠brica de cerveza de la Zaragozana. Estas acequias, en servicio de toda la vida para el abastecimiento de las numerosas industrias y factor‚Ēú¬°as de la zona, ahora eran asociadas con un provinciano pasado agr‚Ēú¬°cola del que Zaragoza hu‚Ēú¬°a como si de la peste de Marsella se tratara, y que hab‚Ēú¬°a que cerrar de forma radical con gruesa capa de cemento armado. A la derecha, modernos utilitarios aparcados donde fuera que hubiera espacio, en este caso junto a la reciente manzana edilicia de la calle de Garc‚Ēú¬°a Lorca. Al fondo, edificios de vivienda de la av. de San Jos‚Ēú¬ģ recayentes a la calle de Juan Jos‚Ēú¬ģ G‚Ēú√≠rate, y el colegio privado sostenido con fondos p‚Ēú‚ēĎblicos "Mar‚Ēú¬°a Auxiliadora" de las salesianas. Fuente visual: fotograf‚Ēú¬°a de Luis Mompel, en Heraldo de Arag‚Ēú‚Ēān.', 1972, 1972, 1972, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.63498800, -0.87967700, '0101000020E6100000786341615026ECBF1DAD6A4947D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35067637151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35067637151.webp', 'https://www.flickr.com/photos/zaragozaantigua/35067637151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22792, 'Calle de Monforte 1971', 'Imagen capturada en la calle de Vicente Monforte y centrada en la tranviaria unidad 214 en servicio en la l‚Ēú¬°nea 11 &quot;Parque-San Jos‚Ēú¬ģ&quot;. Por esta josefina y antigua calle estaba trazado un tramo del bucle que por las calles de Mill‚Ēú√≠n Astray, Monforte y Suiza, permit‚Ēú¬°a a los tranv‚Ēú¬°as dar la vuelta hasta la terminal-principio de l‚Ēú¬°nea en la paralela avenida de San Jos‚Ēú¬ģ. Esta unidad estuvo en servicio hasta 1976, cuando la l‚Ēú¬°nea 11 fue desmantelada y el tranv‚Ēú¬°a desguazado. Como marco edilicio, y de izquierda a derecha, vista parcial del antiguo inmueble del n‚Ē¨‚ēĎ 12 (desaparecido), los n‚Ē¨‚ēĎ 10, 8 Dpdo., 8, 6, y las antiguas parcelas de los n‚Ē¨‚ēĎ 4 Dpdo. y 4 (desaparecidas). Fuente visual: Jos‚Ēú¬ģ Mar‚Ēú¬°a Valero Su‚Ēú√≠rez, Centenario del tranv‚Ēú¬°a el‚Ēú¬ģctrico. Zaragoza, 1902-2002.', 1971, 1971, 1971, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.63658400, -0.87891500, '0101000020E6100000C7D79E591220ECBF1494A2957BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41473748034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41473748034.webp', 'https://www.flickr.com/photos/zaragozaantigua/41473748034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22820, 'Avenida de San Jos‚Ēú¬ģ 1974', 'In‚Ēú¬ģdita imagen capturada desde la altura del n‚Ē¨‚ēĎ 137 de la avenida de San Jos‚Ēú¬ģ, inmueble donde estaba radicado el restaurante Fuji-Yama, todo un referente social desde su inauguraci‚Ēú‚Ēān en 1960, y donde tambi‚Ēú¬ģn estaba radicada la Comisi‚Ēú‚Ēān de Festejos del barrio de San Jos‚Ēú¬ģ. La fotograf‚Ēú¬°a se centra en Mar‚Ēú¬°a Teresa Alcaine Moreu, designada Reina de las Fiestas del barrio a celebrar entre el 24 y el 1 de septiembre de ese a‚Ēú‚Ėío. Hacia el fondo, escena urbana donde destaca el cruce de la avenida con la calle del Tenor Fleta y la moderna guarder‚Ēú¬°a de Santa Mar‚Ēú¬°a del Pilar, construida sobre una parte de la antigua Torre de los Fleta que originalmente dio nombre a esa calle. Sobre el firme de la avenida, v‚Ēú¬°as de la l‚Ēú¬°nea 11 del tranv‚Ēú¬°a "Parque-San Jos‚Ēú¬ģ".', 1974, 1974, 1974, 'Anos 70', 'SAN JOS‚Ēú√ę', 41.63787300, -0.87654500, '0101000020E61000003F1D8F19A80CECBF2E008DD2A5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51633355729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51633355729.webp', 'https://www.flickr.com/photos/zaragozaantigua/51633355729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23164, 'Puerto fluvial 2007', 'Foto: Maite Fern‚Ēú√≠ndez. Obras de construcci‚Ēú‚Ēān del puerto fluvial de Vadorrey, en el r‚Ēú¬°o Ebro. Este fue el lugar elegido para dar abrigo a las 20 embarcaciones que surcar‚Ēú¬°an el r‚Ēú¬°o gracias al nuevo azud (al fondo). La infraestructura de navegaci‚Ēú‚Ēān se complet‚Ēú‚Ēā con el muelle de la Expo (que apenas se pudo utilizar, debido a supuestos imponderables) y el del Club N‚Ēú√≠utico. Todo result‚Ēú‚Ēā ser un verdadero fiasco, que requiri‚Ēú‚Ēā rebajar la solera del puente de Piedra, realizar continuos dragados en el recorrido y finalmente cancelar el servicio en 2016, tras los ‚Ēú‚ēĎltimos viajes de 2015. Fuente: Heraldo de Arag‚Ēú‚Ēān.', 2007, 2007, 2007, 'Siglo XXI', 'LAS FUENTES', 41.65290200, -0.86015400, '0101000020E610000033C170AE6186EBBF1ABFF04A92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32615253085.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32615253085.webp', 'https://www.flickr.com/photos/zaragozaantigua/32615253085/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
